import{_ as a,m as r,k as t,ah as i}from"./chunks/framework.HEc25T99.js";const c=JSON.parse('{"title":"Release notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"src/en/release-notes.md"}'),n={name:"release-notes.md"};function o(l,e,s,h,d,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release notes&quot;">​</a></h1><h2 id="v0-9-2-–-june-2026" tabindex="-1">v0.9.2 – June 2026 <a class="header-anchor" href="#v0-9-2-–-june-2026" aria-label="Permalink to &quot;v0.9.2 – June 2026&quot;">​</a></h2><p>Menu item links are now more flexible to configure. Minor bug fixes. Several internal libraries updated.</p><h2 id="v0-9-1-—-may-2026" tabindex="-1">v0.9.1 — May 2026 <a class="header-anchor" href="#v0-9-1-—-may-2026" aria-label="Permalink to &quot;v0.9.1 — May 2026&quot;">​</a></h2><p>Replaced the color picker with a more reliable version. Some action buttons now remain visible when scrolling the page. Several internal libraries updated.</p><h2 id="v0-9-0-—-may-2026" tabindex="-1">v0.9.0 — May 2026 <a class="header-anchor" href="#v0-9-0-—-may-2026" aria-label="Permalink to &quot;v0.9.0 — May 2026&quot;">​</a></h2><p>Partial redesign of the main layout. Improved news pages display. Search bars now look and behave consistently across the application. General responsiveness improvements.</p><h2 id="v0-8-5-—-april-2026" tabindex="-1">v0.8.5 — April 2026 <a class="header-anchor" href="#v0-8-5-—-april-2026" aria-label="Permalink to &quot;v0.8.5 — April 2026&quot;">​</a></h2><p>Replaced an internal encryption library with a lighter, more actively maintained alternative. Improved error handling. Added autocomplete to login forms. Several internal libraries updated.</p><h2 id="v0-8-4-—-april-2026" tabindex="-1">v0.8.4 — April 2026 <a class="header-anchor" href="#v0-8-4-—-april-2026" aria-label="Permalink to &quot;v0.8.4 — April 2026&quot;">​</a></h2><p>Improved navigation menu management: new item creation form, support for multiple item types, and various bug fixes. Newly created pages now automatically appear at the bottom of the list.</p><h2 id="v0-8-3-—-april-2026" tabindex="-1">v0.8.3 — April 2026 <a class="header-anchor" href="#v0-8-3-—-april-2026" aria-label="Permalink to &quot;v0.8.3 — April 2026&quot;">​</a></h2><p>Fixed a bug with the media library file uploader. Several internal libraries updated.</p><h2 id="v0-8-2-—-april-2026" tabindex="-1">v0.8.2 — April 2026 <a class="header-anchor" href="#v0-8-2-—-april-2026" aria-label="Permalink to &quot;v0.8.2 — April 2026&quot;">​</a></h2><p>Available languages can now be configured directly in the application settings.</p><h2 id="v0-8-1-—-april-2026" tabindex="-1">v0.8.1 — April 2026 <a class="header-anchor" href="#v0-8-1-—-april-2026" aria-label="Permalink to &quot;v0.8.1 — April 2026&quot;">​</a></h2><p>Various fixes to the plugin system. Several internal libraries updated.</p><h2 id="v0-8-0-—-march-2026" tabindex="-1">v0.8.0 — March 2026 <a class="header-anchor" href="#v0-8-0-—-march-2026" aria-label="Permalink to &quot;v0.8.0 — March 2026&quot;">​</a></h2><p>New plugin management page with improved activation and deactivation. Performance improvements.</p><h2 id="v0-7-7-—-march-2026" tabindex="-1">v0.7.7 — March 2026 <a class="header-anchor" href="#v0-7-7-—-march-2026" aria-label="Permalink to &quot;v0.7.7 — March 2026&quot;">​</a></h2><p>Content management improvements: page search in the sidebar, ability to reorder pages, and support for link titles in page sections.</p><h2 id="v0-7-5-—-march-2026" tabindex="-1">v0.7.5 — March 2026 <a class="header-anchor" href="#v0-7-5-—-march-2026" aria-label="Permalink to &quot;v0.7.5 — March 2026&quot;">​</a></h2><p>In development mode, raw data for content items is now accessible to help with debugging. Several internal libraries updated.</p><h2 id="v0-7-4-—-february-2026" tabindex="-1">v0.7.4 — February 2026 <a class="header-anchor" href="#v0-7-4-—-february-2026" aria-label="Permalink to &quot;v0.7.4 — February 2026&quot;">​</a></h2><p>Responsive UI improvements for all screen sizes. Fixed a bug related to data structure settings. Several internal libraries updated.</p><h2 id="v0-7-3-—-february-2026" tabindex="-1">v0.7.3 — February 2026 <a class="header-anchor" href="#v0-7-3-—-february-2026" aria-label="Permalink to &quot;v0.7.3 — February 2026&quot;">​</a></h2><p>Numerous improvements to the visual editor: better section field management and form generation.</p><h2 id="v0-7-2-—-february-2026" tabindex="-1">v0.7.2 — February 2026 <a class="header-anchor" href="#v0-7-2-—-february-2026" aria-label="Permalink to &quot;v0.7.2 — February 2026&quot;">​</a></h2><p>Improvements to the initial setup wizard: enhanced database creation and bug fixes.</p><h2 id="v0-7-1-—-february-2026" tabindex="-1">v0.7.1 — February 2026 <a class="header-anchor" href="#v0-7-1-—-february-2026" aria-label="Permalink to &quot;v0.7.1 — February 2026&quot;">​</a></h2><p>The icon picker in application settings can now be configured to return the icon name.</p><h2 id="v0-7-0-—-february-2026" tabindex="-1">v0.7.0 — February 2026 <a class="header-anchor" href="#v0-7-0-—-february-2026" aria-label="Permalink to &quot;v0.7.0 — February 2026&quot;">​</a></h2><p>Complete overhaul of the access and authentication system with a cleaner architecture.</p><h2 id="v0-6-x-—-december-2025-–-january-2026" tabindex="-1">v0.6.x — December 2025 – January 2026 <a class="header-anchor" href="#v0-6-x-—-december-2025-–-january-2026" aria-label="Permalink to &quot;v0.6.x — December 2025 – January 2026&quot;">​</a></h2><p>Video metadata and visibility management. Bug fixes for the visual editor.</p><h2 id="v0-6-0-—-december-2025" tabindex="-1">v0.6.0 — December 2025 <a class="header-anchor" href="#v0-6-0-—-december-2025" aria-label="Permalink to &quot;v0.6.0 — December 2025&quot;">​</a></h2><p>Launch of the visual editor: manage page sections directly from the interface via a dedicated sidebar.</p><h2 id="v0-5-0-rc-x-—-september–november-2025" tabindex="-1">v0.5.0-rc.x — September–November 2025 <a class="header-anchor" href="#v0-5-0-rc-x-—-september–november-2025" aria-label="Permalink to &quot;v0.5.0-rc.x — September–November 2025&quot;">​</a></h2><p>Gradual improvements to the visual editor: data copying between sections, drag-and-drop reordering, preview mode, and better content model management.</p><h2 id="v0-5-0-rc-1-—-september-2025" tabindex="-1">v0.5.0-rc.1 — September 2025 <a class="header-anchor" href="#v0-5-0-rc-1-—-september-2025" aria-label="Permalink to &quot;v0.5.0-rc.1 — September 2025&quot;">​</a></h2><p>Major update: main layout redesign, media library improvements, and rich text editor upgrade.</p><h2 id="v0-0-17-—-august-2025" tabindex="-1">v0.0.17 — August 2025 <a class="header-anchor" href="#v0-0-17-—-august-2025" aria-label="Permalink to &quot;v0.0.17 — August 2025&quot;">​</a></h2><p>Performance improvements: faster loading for articles, newsletters, and other content.</p><h2 id="v0-0-16-—-may-2025" tabindex="-1">v0.0.16 — May 2025 <a class="header-anchor" href="#v0-0-16-—-may-2025" aria-label="Permalink to &quot;v0.0.16 — May 2025&quot;">​</a></h2><p>Introduction of the plugin system.</p><h2 id="v0-0-14-—-april-2025" tabindex="-1">v0.0.14 — April 2025 <a class="header-anchor" href="#v0-0-14-—-april-2025" aria-label="Permalink to &quot;v0.0.14 — April 2025&quot;">​</a></h2><p>Auto-translation support in multilingual fields. User import and export functionality.</p><h2 id="v0-0-13-—-march-2025" tabindex="-1">v0.0.13 — March 2025 <a class="header-anchor" href="#v0-0-13-—-march-2025" aria-label="Permalink to &quot;v0.0.13 — March 2025&quot;">​</a></h2><p>New field types in the form generator: date/time, time ranges, month, quarter, and week.</p><h2 id="v0-0-10-—-march-2025" tabindex="-1">v0.0.10 — March 2025 <a class="header-anchor" href="#v0-0-10-—-march-2025" aria-label="Permalink to &quot;v0.0.10 — March 2025&quot;">​</a></h2><p>Added list and multilingual list fields to the form generator.</p><h2 id="v0-0-8-—-february-2025" tabindex="-1">v0.0.8 — February 2025 <a class="header-anchor" href="#v0-0-8-—-february-2025" aria-label="Permalink to &quot;v0.0.8 — February 2025&quot;">​</a></h2><p>Mobile UI improvements. Configurable limit on multiple selections.</p><h2 id="v0-0-5-—-january-2025" tabindex="-1">v0.0.5 — January 2025 <a class="header-anchor" href="#v0-0-5-—-january-2025" aria-label="Permalink to &quot;v0.0.5 — January 2025&quot;">​</a></h2><p>Numerous fixes and new features: permalink management, media picker, auto-updating sections, section position display, and pagination fixes.</p><h2 id="v0-0-2-—-january-2025" tabindex="-1">v0.0.2 — January 2025 <a class="header-anchor" href="#v0-0-2-—-january-2025" aria-label="Permalink to &quot;v0.0.2 — January 2025&quot;">​</a></h2><p>First public release: dashboard with visits map and video management.</p>',57)])])}const m=a(n,[["render",o]]);export{c as __pageData,m as default};
